+    private static IMethodSymbol? FindSingleArgCtor(INamedTypeSymbol target, ITypeSymbol sourceType, SymbolAccessor symbolAccessor)
+    {
+        var ctorCandidates = target.InstanceConstructors.Where(symbolAccessor.IsConstructorAccessible).ToArray();
+        var configuredCtorCandidates = ctorCandidates.Where(x => symbolAccessor.HasAttribute<MapperConstructorAttribute>(x)).ToArray();
+        if (configuredCtorCandidates.Length > 0)
+        {
+            ctorCandidates = configuredCtorCandidates;
+        }
+
+        return ctorCandidates.FirstOrDefault(m =>
+            m.Parameters.Length == 1
+            && SymbolEqualityComparer.Default.Equals(m.Parameters[0].Type.NonNullable(), sourceType.NonNullable())
+            && sourceType.HasSameOrStricterNullability(m.Parameters[0].Type)
+        );
+    }
